designSystem.cssContract:

:root {
  --oc-bg: #080B12;
  --oc-panel: #101624;
  --oc-panel-raised: #151D2E;
  --oc-border: #263246;
  --oc-text: #E7ECF5;
  --oc-text-2: #AAB6C8;
  --oc-muted: #6F7E93;
  --oc-positive: #3ED598;
  --oc-warning: #F6C85F;
  --oc-danger: #FF6B6B;
  --oc-info: #6EA8FE;
  --oc-purple: #A78BFA;
  --oc-radius: 14px;
  --oc-shadow: 0 18px 60px rgba(0,0,0,0.28);
}
.oc-shell { min-height: 100vh; background: radial-gradient(circle at top left, rgba(110,168,254,0.08), transparent 28rem), var(--oc-bg); color: var(--oc-text); }
.oc-layout { display: grid; grid-template-columns: 280px minmax(0, 1fr); min-height: 100vh; }
.oc-sidebar { border-right: 1px solid var(--oc-border); background: rgba(16,22,36,0.88); position: sticky; top: 0; height: 100vh; overflow: auto; }
.oc-main { min-width: 0; padding: 20px 24px 40px; }
.oc-topbar { display: flex; align-items: center; justify-content: space-between; gap: 16px; margin-bottom: 18px; }
.oc-status-strip { display: grid; grid-template-columns: repeat(6, minmax(0, 1fr)); gap: 10px; margin-bottom: 18px; }
.oc-card { background: linear-gradient(180deg, rgba(21,29,46,0.96), rgba(16,22,36,0.96)); border: 1px solid var(--oc-border); border-radius: var(--oc-radius); box-shadow: var(--oc-shadow); }
.oc-card-header { padding: 16px 18px 0; display: flex; justify-content: space-between; gap: 12px; align-items: start; }
.oc-card-body { padding: 16px 18px 18px; }
.oc-grid-2 { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 16px; }
.oc-grid-3 { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 16px; }
.oc-grid-4 { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 12px; }
.oc-kpi { padding: 14px; border: 1px solid var(--oc-border); border-radius: 12px; background: rgba(255,255,255,0.025); }
.oc-kpi-label { color: var(--oc-muted); font-size: 12px; text-transform: uppercase; letter-spacing: 0.08em; }
.oc-kpi-value { font-size: 24px; font-weight: 720; margin-top: 6px; }
.oc-badge { display: inline-flex; align-items: center; gap: 6px; border-radius: 999px; border: 1px solid var(--oc-border); padding: 4px 9px; font-size: 12px; font-weight: 650; white-space: nowrap; }
.oc-badge.ok { color: var(--oc-positive); border-color: rgba(62,213,152,0.38); background: rgba(62,213,152,0.08); }
.oc-badge.warn { color: var(--oc-warning); border-color: rgba(246,200,95,0.38); background: rgba(246,200,95,0.08); }
.oc-badge.danger { color: var(--oc-danger); border-color: rgba(255,107,107,0.38); background: rgba(255,107,107,0.08); }
.oc-badge.info { color: var(--oc-info); border-color: rgba(110,168,254,0.38); background: rgba(110,168,254,0.08); }
.oc-table { width: 100%; border-collapse: separate; border-spacing: 0; }
.oc-table th { color: var(--oc-muted); font-size: 11px; text-transform: uppercase; letter-spacing: 0.08em; text-align: left; padding: 10px 12px; border-bottom: 1px solid var(--oc-border); }
.oc-table td { padding: 12px; border-bottom: 1px solid rgba(38,50,70,0.72); vertical-align: top; }
.oc-link { color: var(--oc-info); text-decoration: none; }
.oc-link:hover { text-decoration: underline; }
.oc-timeline { position: relative; display: grid; gap: 12px; }
.oc-timeline-item { display: grid; grid-template-columns: 120px minmax(0,1fr); gap: 14px; padding: 12px; border: 1px solid var(--oc-border); border-radius: 12px; background: rgba(255,255,255,0.022); }
.oc-evidence-list { display: grid; gap: 8px; margin: 0; padding: 0; list-style: none; }
.oc-evidence-item { display: grid; grid-template-columns: 160px minmax(0,1fr) auto; gap: 10px; align-items: center; padding: 8px 10px; border-radius: 10px; background: rgba(255,255,255,0.024); border: 1px solid rgba(38,50,70,0.65); }
.oc-reason { line-height: 1.55; color: var(--oc-text-2); }
.oc-reason strong { color: var(--oc-text); }
.oc-empty { padding: 18px; border: 1px dashed rgba(170,182,200,0.3); border-radius: 12px; color: var(--oc-muted); }
.oc-code { font-family: var(--oc-mono, monospace); color: var(--oc-text-2); font-size: 12px; }
@media (max-width: 1100px) { .oc-layout { grid-template-columns: 1fr; } .oc-sidebar { position: static; height: auto; } .oc-status-strip, .oc-grid-3, .oc-grid-4 { grid-template-columns: repeat(2, minmax(0, 1fr)); } }
@media (max-width: 720px) { .oc-main { padding: 14px; } .oc-status-strip, .oc-grid-2, .oc-grid-3, .oc-grid-4 { grid-template-columns: 1fr; } .oc-timeline-item { grid-template-columns: 1fr; } .oc-evidence-item { grid-template-columns: 1fr; } }
